/** Helper : récupère la traduction d'une catégorie splittable (ex: 'Garde,Activité,...') */
export function tList(key: string, lang: LangCode): string[] {
  const entry = T[key];
  if (!entry) return [];
  return entry[lang].split(',').map((s: string) => s.trim());
}

/** Helper : jours de la semaine abrégés */
export function weekDays(lang: LangCode): string[] {
  return ['mon','tue','wed','thu','fri','sat','sun'].map((k) => T[`day.${k}`]?.[lang] ?? k);
}

/** Helper : mois abrégés */
export function shortMonths(lang: LangCode): string[] {
  return ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec']
    .map((k) => T[`month.${k}`]?.[lang] ?? k);
}
